create table roma_main.ftth_dubletten_bewertung (
    id          number
        generated by default on null as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 start with 1 cache 20
        noorder nocycle nokeep noscale
    not null enable,
    knr0        varchar2(30 byte) not null enable,
    knr1        varchar2(30 byte) not null enable,
    fuzzy_rowid varchar2(30 byte),
    bewertung   varchar2(3 byte),
    datum       date not null enable,
    username    varchar2(30 byte) not null enable,
    kommentar   varchar2(1000 char),
    aktuell     number(1, 0)
);

alter table roma_main.ftth_dubletten_bewertung
    add constraint ftth_dubletten_bewertung_pk primary key ( id )
        using index enable;


